// New: an optional codec, configured per endpoint.
pub struct CodecConfig {
    pub framing:  Option<FramingConfig>,
    pub decoding: Option<DeserializerConfig>,
}

impl CodecConfig {
    fn build_decoder(&self, ns: LogNamespace) -> Result<Option<Decoder>> {
        match &self.decoding {
            Some(decoding) => {
                let framing = self.framing.clone().unwrap_or_else(
                    || decoding.default_message_based_framing());
                Ok(Some(DecodingConfig::new(framing, decoding, ns).build()?))
            }
            None => Ok(None),   // unset -> legacy behavior, unchanged
        }
    }
}

